const p = $json;
const name = p.name;
return [{ json: {
  pokemon_id: p.id,
  name: name,
  height: p.height,
  weight: p.weight,
  base_xp: p.base_experience,
  image_url: (p.sprites && p.sprites.other && p.sprites.other['official-artwork'] && p.sprites.other['official-artwork'].front_default) || p.sprites.front_default,
  bucket_raw: 'raw-pokemon',
  object_key_raw: name + '/raw.json',
  bucket_img: 'pokemon-images',
  object_key_img: name + '/official-artwork.png',
  raw_json: JSON.stringify(p)
} }];
